下面给你一个“仿照你现有结构”的**多图（多帧）请求示例**：核心点是把多张图片都放进同一条 message 的 `content` 列表里（多次 `{"type":"image_url"...}`），并用 `data:image/jpeg;base64,...` 方式传给 OpenAI 兼容接口。示例也保留了 `ProcessPoolExecutor + init_client()` 的写法。

> 注意：你在 vLLM 启动时设置了 `--limit-mm-per-prompt '{"image":1,"video":0}'`，这会限制**每个请求只能带 1 张图**。  
> 如果你要真正“多图”一次性发过去，需要把它改大，比如：`'{"image":8,"video":0}'`。否则多图请求会报错或被拒绝。

---

```python
import os
import base64
from pathlib import Path
from openai import OpenAI
from concurrent.futures import ProcessPoolExecutor, as_completed
import multiprocessing
from PIL import Image
import io
import json

# ===== 配置参数 =====
INPUT_JSON_PATH = "/path/to/input_images.json"   # 例如: [{"id":"case1","images":["/a.jpg","/b.jpg"]}, ...]
OUTPUT_JSON = "/path/to/output_multiimage.json"
MAX_WORKERS = 8
MODEL_NAME = "qwen3vl"  # 你 vLLM 的 --served-model-name

Path(OUTPUT_JSON).parent.mkdir(parents=True, exist_ok=True)

client_cfg = {
    "base_url": "http://10.140.158.150:22229/v1",
    "api_key": "EMPTY",
}

def init_client():
    return OpenAI(**client_cfg)

def encode_image_file_to_base64(image_path: str) -> str:
    """读取图片并编码为 base64 jpeg（统一转成 JPEG 更稳）"""
    img = Image.open(image_path).convert("RGB")
    buf = io.BytesIO()
    img.save(buf, format="JPEG", quality=85)
    return base64.b64encode(buf.getvalue()).decode("utf-8")

def build_multi_image_messages(image_paths, prompt: str):
    """构造 OpenAI 兼容的多图 messages"""
    content = [{"type": "text", "text": prompt}]

    for p in image_paths:
        b64 = encode_image_file_to_base64(p)
        content.append({
            "type": "image_url",
            "image_url": {"url": f"data:image/jpeg;base64,{b64}"}
        })

    return [{"role": "user", "content": content}]

def describe_multiple_images(image_paths, prompt: str, client: OpenAI) -> str:
    messages = build_multi_image_messages(
        image_paths=image_paths,
        prompt=prompt
    )
    resp = client.chat.completions.create(
        model=MODEL_NAME,
        messages=messages,
        max_tokens=512,
        temperature=0.2,
    )
    return resp.choices[0].message.content.strip()

def process_item(item: dict):
    """
    item 结构示例：
    {
      "id": "case1",
      "images": ["/path/1.jpg", "/path/2.jpg", ...]
    }
    """
    cid = item.get("id", "unknown")
    image_paths = item.get("images", [])

    # 每个进程单独初始化 client（避免多进程共享连接问题）
    client = init_client()

    if not image_paths:
        return cid, {"error": "no images"}

    # 你可以在 prompt 里要求“按顺序对比/总结”
    prompt = (
        "下面是一组按时间顺序排列的图片。"
        "请综合所有图片，给出一段简洁描述，说明发生了什么/场景如何变化。"
        "如果有关键物体或动作，请点出来。"
    )

    try:
        text = describe_multiple_images(image_paths, prompt, client)
        return cid, {"caption": text, "num_images": len(image_paths)}
    except Exception as e:
        return cid, {"error": str(e), "num_images": len(image_paths)}

def main():
    with open(INPUT_JSON_PATH, "r", encoding="utf-8") as f:
        items = json.load(f)

    results = {}
    with ProcessPoolExecutor(max_workers=MAX_WORKERS) as ex:
        futs = [ex.submit(process_item, item) for item in items]
        for fut in as_completed(futs):
            cid, out = fut.result()
            results[cid] = out
            if "error" in out:
                print(f"❌ {cid}: {out['error']}")
            else:
                print(f"✅ {cid}: {out['num_images']} images")

    with open(OUTPUT_JSON, "w", encoding="utf-8") as f:
        json.dump(results, f, indent=2, ensure_ascii=False)

    print(f"✅ saved to: {OUTPUT_JSON}")

if __name__ == "__main__":
    multiprocessing.set_start_method("spawn", force=True)
    main()
```

